/**
 * Component Parameter Schema Types
 *
 * These types match the JSON Schema format generated by the okapi-bridge
 * schema generator and the Go schema.FromStruct() reflection helper,
 * with ui: extensions for UI rendering.
 *
 * Both filters and tools use the same schema format. FilterSchema is a
 * specialization of ComponentSchema with filter-specific metadata.
 */

/** Generalized component schema — works for both filters and tools. */
export interface ComponentSchema {
  $id?: string;
  $version?: string;
  title: string;
  description?: string;
  type: string;
  formatMeta?: FormatMeta;
  toolMeta?: ToolMeta;
  presets?: Record<string, Record<string, unknown>>;
  "ui:groups"?: ParameterGroup[];
  "x-apiVersion"?: string;
  "x-introducedInOkapi"?: string;
  properties?: Record<string, PropertySchema>;
  $defs?: Record<string, PropertySchema>;
}

/** Filter-specific schema (backward compatible specialization). */
export interface FilterSchema extends ComponentSchema {
  formatMeta: FormatMeta;
}

export interface FormatMeta {
  id: string;
  extensions?: string[];
  mimeTypes?: string[];
}

/** Tool metadata. */
export interface ToolMeta {
  id?: string;
  displayName?: string;
  description?: string;
  category?: string;
  inputs?: string[];
  outputs?: string[];
  tags?: string[];
  requires?: string[];
}

export interface ParameterGroup {
  id: string;
  label: string;
  description?: string;
  collapsible?: boolean;
  collapsed?: boolean;
  icon?: string;
  fields: string[];
}

/**
 * Condition expression for ui:visible and ui:enabled.
 */
export type ConditionExpr =
  | { field: string; eq: unknown }
  | { field: string; empty: boolean }
  | { all: ConditionExpr[] }
  | { any: ConditionExpr[] }
  | { not: ConditionExpr };

export interface PropertySchema {
  type: string;
  title?: string;
  description?: string;
  default?: unknown;
  deprecated?: boolean;
  enum?: unknown[];
  minimum?: number;
  maximum?: number;

  // Nested object properties
  properties?: Record<string, PropertySchema>;
  additionalProperties?: PropertySchema | boolean;
  items?: PropertySchema;
  required?: string[];
  $ref?: string;

  // UI hints (ui: prefix)
  "ui:widget"?: string;
  "ui:placeholder"?: string;
  "ui:presets"?: Record<string, unknown>;
  "ui:order"?: number;
  "ui:visible"?: ConditionExpr;
  "ui:enabled"?: ConditionExpr;
  "ui:enum-labels"?: Record<string, string>;
  "ui:enum-descriptions"?: Record<string, string>;
  "ui:introduced-in"?: string;

  // Okapi bridge extensions
  "x-okapi-flatten-path"?: string;
  "x-okapi-format"?: string;
}

/**
 * CodeFinderRules value structure (clean JSON format).
 */
export interface CodeFinderRulesValue {
  rules: Array<{ pattern: string }>;
  sample?: string;
  useAllRulesWhenTesting?: boolean;
}

/**
 * Filter parameters value type.
 */
export type FilterParamsValue = Record<string, unknown>;
